const p = msg.payload;
if (!p || typeof p !== 'object') return null;

// 1) Full document for any consumer that wants it
flow.set('bms_latest', p);
flow.set('bms_latest_at', Math.floor(Date.now() / 1000));

// 2) Project-specific mapping into the global telemetry the dashboard
//    composer (fn_assemble) already reads. We only touch the bms-derived
//    keys; everything else stays as set by the other handlers.
const t = global.get('telemetry') || {};
if (typeof p.soc_pct    === 'number') t.house_battery_percent = p.soc_pct;
if (typeof p.voltage_v  === 'number') t.house_battery_voltage = p.voltage_v;
if (typeof p.current_a  === 'number') t.house_battery_current = p.current_a;
if (typeof p.power_w    === 'number') t.house_battery_power   = p.power_w;
global.set('telemetry', t);

// 3) Status badge
const soc = p.soc_pct, v = p.voltage_v, i = p.current_a;
node.status({
    fill:  p.protection_active ? 'red' : 'green',
    shape: 'dot',
    text:  `${soc}% ${v}V ${i >= 0 ? '+' : ''}${i}A @ ${new Date().toLocaleTimeString()}`
});
return msg;

// Per-metric decimation. Splits one BMS document into 1..N influx writes,
// each shaped as msg.payload = [fieldsObj, tagsObj] + msg.measurement = ...
// Returns a single output that is an array of messages.
const p = msg.payload;
if (!p || typeof p !== 'object') return null;

const now = Date.now();
const out = [];
const tagsBase = { device: 'main' };

// ─── HOT (every tick, ~30 s) ─────────────────────────────────────────
out.push({
    measurement: 'bms_live',
    payload: [
        {
            voltage_v:          p.voltage_v          ?? null,
            current_a:          p.current_a          ?? null,
            power_w:            p.power_w            ?? null,
            soc_pct:            p.soc_pct            ?? null,
            remaining_ah:       p.remaining_ah       ?? null,
            charging_mosfet:    p.charging_mosfet    ? 1 : 0,
            discharging_mosfet: p.discharging_mosfet ? 1 : 0,
            balance_active:     p.balance_active     ? 1 : 0,
            protection_active:  p.protection_active  ? 1 : 0,
        },
        tagsBase,
    ],
});

const num = (v, fallback = 0) => (typeof v === 'number' && isFinite(v)) ? v : fallback;

// ─── MEDIUM (5 min, or on protection / balance / cell-delta change) ──
const lastMedAt    = flow.get('bms_inf_med_at')    || 0;
const lastDelta    = flow.get('bms_inf_med_delta') ?? 0;
const lastProt     = flow.get('bms_inf_med_prot')  ?? null;
const lastBal      = flow.get('bms_inf_med_bal')   ?? null;
const medThreshMs  = 5 * 60 * 1000;
const medChange    =
    Math.abs(num(p.cell_delta_v) - lastDelta) > 0.005 ||
    p.protection_active !== lastProt ||
    p.balance_active    !== lastBal;

if (now - lastMedAt > medThreshMs || medChange) {
    out.push({
        measurement: 'bms_state',
        payload: [
            {
                cell_min_v:   p.cell_min_v   ?? null,
                cell_max_v:   p.cell_max_v   ?? null,
                cell_delta_v: p.cell_delta_v ?? null,
                cell_min_idx: p.cell_min_idx ?? null,
                cell_max_idx: p.cell_max_idx ?? null,
            },
            tagsBase,
        ],
    });
    flow.set('bms_inf_med_at',    now);
    flow.set('bms_inf_med_delta', num(p.cell_delta_v));
    flow.set('bms_inf_med_prot',  p.protection_active);
    flow.set('bms_inf_med_bal',   p.balance_active);
}

// ─── PER-CELL (10 min, or on >5 mV per-cell change) ──────────────────
const lastCellsAt = flow.get('bms_inf_cells_at') || 0;
const lastCells   = flow.get('bms_inf_cells_v')  || [];
const cellsThreshMs = 10 * 60 * 1000;
const cells = Array.isArray(p.cells_v) ? p.cells_v : [];
const cellsChanged =
    cells.length !== lastCells.length ||
    cells.some((v, i) => Math.abs(v - (lastCells[i] ?? 0)) > 0.005);

if (cells.length && (now - lastCellsAt > cellsThreshMs || cellsChanged)) {
    cells.forEach((v, i) => {
        out.push({
            measurement: 'bms_cells',
            payload: [{ voltage_v: v }, { ...tagsBase, cell_idx: String(i + 1) }],
        });
    });
    flow.set('bms_inf_cells_at', now);
    flow.set('bms_inf_cells_v',  cells.slice());
}

// ─── PER-NTC TEMPS (10 min, or on >0.5 °C change) ────────────────────
const lastTempsAt = flow.get('bms_inf_temps_at') || 0;
const lastTemps   = flow.get('bms_inf_temps_v')  || [];
const tempsThreshMs = 10 * 60 * 1000;
const temps = Array.isArray(p.temperatures_c) ? p.temperatures_c : [];
const tempsChanged =
    temps.length !== lastTemps.length ||
    temps.some((v, i) => Math.abs(v - (lastTemps[i] ?? 0)) > 0.5);

if (temps.length && (now - lastTempsAt > tempsThreshMs || tempsChanged)) {
    temps.forEach((t, i) => {
        out.push({
            measurement: 'bms_temps',
            payload: [{ temp_c: t }, { ...tagsBase, ntc_idx: String(i + 1) }],
        });
    });
    flow.set('bms_inf_temps_at', now);
    flow.set('bms_inf_temps_v',  temps.slice());
}

// ─── STATIC (hourly) ─────────────────────────────────────────────────
const lastMetaAt = flow.get('bms_inf_meta_at') || 0;
if (now - lastMetaAt > 60 * 60 * 1000) {
    out.push({
        measurement: 'bms_meta',
        payload: [
            {
                cycle_count: p.cycle_count ?? null,
                capacity_ah: p.capacity_ah ?? null,
                cell_count:  p.cell_count  ?? null,
                ntc_count:   p.ntc_count   ?? null,
            },
            tagsBase,
        ],
    });
    flow.set('bms_inf_meta_at', now);
}

node.status({ fill: 'blue', shape: 'dot', text: `${out.length} write(s) @ ${new Date().toLocaleTimeString()}` });
return [out];

const status = (typeof msg.payload === 'string') ? msg.payload : 'unknown';
flow.set('bms_status', status);
node.status({
    fill:  status === 'online' ? 'green' : 'red',
    shape: 'dot',
    text:  status
});
if (status !== 'online') {
    // bridge is down — wipe the live BMS fields from telemetry so the
    // dashboard doesn't show stale values; fn_assemble will emit nulls.
    const t = global.get('telemetry') || {};
    delete t.house_battery_percent;
    delete t.house_battery_voltage;
    delete t.house_battery_current;
    delete t.house_battery_power;
    global.set('telemetry', t);
}
return null;
